import Phaser from 'phaser';

const createHeroAnims = (anims: Phaser.Animations.AnimationManager) =>
{
    anims.create({
        key: 'hero-idle',
        frames: [
            {
                key: 'hero',
                frame: 'frame-0-0.png',
                duration: 640
            },
            {
                key: 'hero',
                frame: 'frame-0-1.png',
               
            },
            {
                key: 'hero',
                frame: 'frame-0-2.png',
                duration: 640
            },
            {
                key: 'hero',
                frame: 'frame-0-1.png',
            }],
        repeat: -1,
        frameRate: 10,
    });

    anims.create({
        key: 'hero-run-down',
        frames: [
            {
                key: 'hero',
                frame: 'frame-2-0.png',
            },
            {
                key: 'hero',
                frame: 'frame-2-1.png',
               
            },
            {
                key: 'hero',
                frame: 'frame-2-2.png',
            },
            {
                key: 'hero',
                frame: 'frame-2-3.png',
            }],
        repeat: -1,
        frameRate: 10,
    });

    anims.create({
        key: 'hero-run-right',
        frames: [
            {
                key: 'hero',
                frame: 'frame-3-0.png',
            },
            {
                key: 'hero',
                frame: 'frame-3-1.png',
               
            },
            {
                key: 'hero',
                frame: 'frame-3-2.png',
            },
            {
                key: 'hero',
                frame: 'frame-3-3.png',
            }],
        repeat: -1,
        frameRate: 10,
    });

    anims.create({
        key: 'hero-run-left',
        frames: [
            {
                key: 'hero_flipped',
                frame: 'frame-3-0.png',
            },
            {
                key: 'hero_flipped',
                frame: 'frame-3-1.png',
               
            },
            {
                key: 'hero_flipped',
                frame: 'frame-3-2.png',
            },
            {
                key: 'hero_flipped',
                frame: 'frame-3-3.png',
            }],
        repeat: -1,
        frameRate: 10,
    });

    anims.create({
        key: 'hero-run-up',
        frames: [
            {
                key: 'hero',
                frame: 'frame-4-0.png',
            },
            {
                key: 'hero',
                frame: 'frame-4-1.png',
               
            },
            {
                key: 'hero',
                frame: 'frame-4-2.png',
            },
            {
                key: 'hero',
                frame: 'frame-4-3.png',
            }],
        repeat: -1,
        frameRate: 10,
    });

    anims.create({
        key: 'hero-attack-down',
        frames:[
            {
                key: 'hero',
                frame: 'frame-5-0.png',
            },
            {
                key: 'hero',
                frame: 'frame-5-1.png',
            },
            {
                key: 'hero',
                frame: 'frame-5-2.png',
            },
            {
                key: 'hero',
                frame: 'frame-5-3.png',
            },

        ]        
    })

    anims.create({
        key: 'hero-attack-right',
        frames:[
            {
                key: 'hero',
                frame: 'frame-6-0.png',
            },
            {
                key: 'hero',
                frame: 'frame-6-1.png',
            },
            {
                key: 'hero',
                frame: 'frame-6-2.png',
            },
            {
                key: 'hero',
                frame: 'frame-6-3.png',
            },

        ]        
    })

    anims.create({
        key: 'hero-attack-left',
        frames:[
            {
                key: 'hero_flipped',
                frame: 'frame-6-0.png',
            },
            {
                key: 'hero_flipped',
                frame: 'frame-6-1.png',
            },
            {
                key: 'hero_flipped',
                frame: 'frame-6-2.png',
            },
            {
                key: 'hero_flipped',
                frame: 'frame-6-3.png',
            },

        ]        
    })

    anims.create({
        key: 'hero-attack-up',
        frames:[
            {
                key: 'hero',
                frame: 'frame-7-0.png',
            },
            {
                key: 'hero',
                frame: 'frame-7-1.png',
            },
            {
                key: 'hero',
                frame: 'frame-7-2.png',
            },
            {
                key: 'hero',
                frame: 'frame-7-3.png',
            },

        ]        
    })
}

export {createHeroAnims};
